function getRosePineIcon(filename) {
    const name = filename.toLowerCase();
    
    if (ICON_MAP.fileNames[name]) {
        return ICON_MAP.fileNames[name];
    }
    
    const parts = name.split('.');
    if (parts.length > 2 && ICON_MAP.extensions[parts.slice(-2).join('.')]) {
        return ICON_MAP.extensions[parts.slice(-2).join('.')];
    }
    
    const ext = parts.pop();
    if (ICON_MAP.extensions[ext]) {
        return ICON_MAP.extensions[ext];
    }
    
    return "icons/file.svg";
}

window.getRosePineIcon = getRosePineIcon;
